## 2️⃣ C++ wrapper – `blocksci_c.cpp`

```cpp
/*=====================================================================
 *  blocksci_c.cpp
 *  C++ implementation of the C API above.
 *
 *  Build command (example):
 *      c++ -std=c++20 -fPIC -shared -o libblocksci_c.so blocksci_c.cpp \
 *          -lblocksci   # <-- link against the real BlockSci lib
 *
 *  The file is deliberately self‑contained: it only depends on the
 *  public BlockSci header <blocksci/blocksci.hpp>.  If you need to
 *  adjust the include path, change the #include line accordingly.
 *====================================================================*/

#include <cstddef>
#include <cstdint>
#include <cstring>
#include <exception>
#include <string>
#include <vector>

#include "blocksci_c.h"               // the public header we just defined
#include <blocksci/blocksci.hpp>      // <-- real BlockSci C++ API (mocked here)

/* --------------------------------------------------------------------
 *  Opaque structures that are visible to C but defined in C++.
 * -------------------------------------------------------------------- */
struct bsci_block_t {
    const blocksci::Block *ptr;   // not owned – lives as long as the iterator
};

struct bsci_iter_t {
    blocksci::Chain chain;        // owns the whole blockchain data
    blocksci::BlockIterator cur;  // current position
    blocksci::BlockIterator end;  // sentinel (one-past-last)
};

/* --------------------------------------------------------------------
 *  Helper: translate C++ exceptions into a static C string.
 * -------------------------------------------------------------------- */
static const char *last_error_msg = nullptr;

static const char *store_error(const std::exception &e) noexcept {
    static std::string buf;
    buf = e.what();          // copy into a static storage (thread‑unsafe)
    last_error_msg = buf.c_str();
    return last_error_msg;
}

/* --------------------------------------------------------------------
 *  API implementation
 * -------------------------------------------------------------------- */
extern "C" {

/* --------------------------------------------------------------------
 *  Open iterator over the whole chain.
 * -------------------------------------------------------------------- */
bsci_iter_t *bsci_iter_open(const char *datadir, const char **error_msg) {
    try {
        bsci_iter_t *it = new bsci_iter_t;
        it->chain = blocksci::Chain(datadir);            // may throw
        it->cur   = it->chain.begin();
        it->end   = it->chain.end();
        if (error_msg) *error_msg = nullptr;
        return it;
    } catch (const std::exception &e) {
        if (error_msg) *error_msg = store_error(e);
        return nullptr;
    }
}

/* --------------------------------------------------------------------
 *  Close iterator – free everything.
 * -------------------------------------------------------------------- */
void bsci_iter_close(bsci_iter_t *it) {
    delete it;   // RAII releases the Chain object
}

/* --------------------------------------------------------------------
 *  One‑shot iteration (the hot path).
 *
 *  The loop is completely in C++ land; the only transition is the
 *  call to the user supplied C function pointer.  No heap allocation,
 *  no virtual dispatch, no extra copies.
 * -------------------------------------------------------------------- */
int bsci_iter_foreach(bsci_iter_t *it,
                      bsci_block_cb cb,
                      void *user_data) {
    if (!it || !cb) return -1;               // sanity check

    // The iterator itself is cheap to copy; we march it forward.
    for (auto itr = it->cur; itr != it->end; ++itr) {
        bsci_block_t blk{ &*itr };           // view into the native block
        int rc = cb(&blk, user_data);        // invoke user code
        if (rc != 0) return rc;              // abort on non‑zero
    }
    return 0;                                 // normal completion
}

/* --------------------------------------------------------------------
 *  Block field accessors – thin wrappers that read from the underlying
 *  C++ object.  All of them are inlined by the compiler (they are tiny).
 * -------------------------------------------------------------------- */
uint32_t bsci_block_height(const bsci_block_t *blk) {
    return static_cast<uint32_t>(blk->ptr->height());
}

uint64_t bsci_block_timestamp(const bsci_block_t *blk) {
    return static_cast<uint64_t>(blk->ptr->timestamp());
}

size_t bsci_block_tx_count(const bsci_block_t *blk) {
    return blk->ptr->txes().size();
}

/* The hash is stored as a 32‑byte array inside BlockSci.  We expose a
 * pointer to that memory; the caller must not free or modify it. */
const uint8_t *bsci_block_hash(const bsci_block_t *blk, size_t *out_len) {
    if (out_len) *out_len = 32;
    return reinterpret_cast<const uint8_t*>(blk->ptr->hash().data());
}

} // extern "C"
```

